command:
const updates = [];

for (const token of canvas.tokens.placeables) {
  const actor = token.actor;
  if (!actor || actor.type !== "npc") continue;
  const hasWounds = actor.system.wounds.max > 0;
  const hasBennies = actor.system.bennies.max > 0;

  updates.push({
    _id: token.document.id,
    "bar1.attribute": hasWounds ? "wounds" : "",
    "bar2.attribute": hasBennies ? "bennies" : "",
    displayBars: CONST.TOKEN_DISPLAY_MODES.ALWAYS
  });
}

if (updates.length) {
  await canvas.scene.updateEmbeddedDocuments("Token", updates);
}
